    </style>
<div class="game-container">
<h1>Word Search: 20 Verbos Irregulares (Pasado Simple) 🔊</h1>
<div class="timer-score-box"><span>Tiempo: <span id="timer">00:00</span></span> <span>Encontradas: <span id="found-count">0</span>/20</span></div>
<div id="word-search-grid"></div>
<h2>Palabras a Encontrar:</h2>
<ul id="words-to-find"></ul>
<p id="feedback" style="text-align: center; font-weight: bold; margin-top: 15px; min-height: 20px;"></p>
<div id="final-score" style="display: none;"></div>
</div>
<script>
    const WORDS = [
        "WENT", "SAW", "RAN", "CAME", "ATE",
        "DRANK", "WROTE", "SLEPT", "SPOKE", "TOOK",
        "GAVE", "MADE", "FELT", "KNEW", "HELD", 
        "LEFT", "READ", "MET", "PUT", "LOST"
    ];
    const GRID_SIZE = 15;
    // Direcciones: Derecha, Abajo, Diag Abajo-Der, Izquierda, Arriba, Diag Arriba-Izq, Diag Abajo-Izq, Diag Arriba-Der
    const DIRECTIONS = [
        [0, 1], [1, 0], [1, 1], [0, -1], [-1, 0], [-1, -1], [1, -1], [-1, 1]
    ];

    const gridEl = document.getElementById('word-search-grid');
    const wordsEl = document.getElementById('words-to-find');
    const feedbackEl = document.getElementById('feedback');
    const timerEl = document.getElementById('timer');
    const foundCountEl = document.getElementById('found-count');
    const finalScoreEl = document.getElementById('final-score');

    let grid = [];
    let placedWords = []; // [{word, cells: [{r, c}, ...]}, ...]
    let foundWords = new Set();

    let isSelecting = false;
    let startCell = null;
    let currentCells = [];

    let startTime;
    let timerInterval;

    // =======================================================
    // NUEVA FUNCIÓN: PRONUNCIACIÓN
    // =======================================================
    function speakWord(word) {
        if ('speechSynthesis' in window) {
            // Cancelar cualquier pronunciación anterior
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance(word);
            // Configurar el idioma en inglés para la pronunciación correcta
            utterance.lang = 'en-US'; 
            window.speechSynthesis.speak(utterance);
        } else {
            console.warn("La síntesis de voz no es compatible con este navegador.");
        }
    }
    // =======================================================
    // 1. GENERADOR DE TABLERO ALEATORIO
    // =======================================================

    function generateGrid() {
        grid = Array(GRID_SIZE).fill(0).map(() => Array(GRID_SIZE).fill(''));
        placedWords = [];

        const shuffledWords = [...WORDS].sort(() => 0.5 - Math.random());

        shuffledWords.forEach(word => {
            let placed = false;
            let attempts = 0;

            while (!placed && attempts < 100) {
                attempts++;

                const startR = Math.floor(Math.random() * GRID_SIZE);
                const startC = Math.floor(Math.random() * GRID_SIZE);
                const [dr, dc] = DIRECTIONS[Math.floor(Math.random() * DIRECTIONS.length)];

                const placementCells = [];
                let isValid = true;

                for (let i = 0; i < word.length; i++) {
                    const r = startR + i * dr;
                    const c = startC + i * dc;

                    if (r < 0 || r >= GRID_SIZE || c < 0 || c >= GRID_SIZE) {
                        isValid = false;
                        break;
                    }

                    const existingChar = grid[r][c];
                    if (existingChar !== '' && existingChar !== word[i]) {
                        isValid = false;
                        break;
                    }

                    placementCells.push({r, c});
                }

                if (isValid && placementCells.length === word.length) {
                    placementCells.forEach((cell, i) => {
                        grid[cell.r][cell.c] = word[i];
                    });

                    placedWords.push({ word, cells: placementCells });
                    placed = true;
                }
            }
        });

        const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        for (let r = 0; r < GRID_SIZE; r++) {
            for (let c = 0; c < GRID_SIZE; c++) {
                if (grid[r][c] === '') {
                    grid[r][c] = alphabet[Math.floor(Math.random() * alphabet.length)];
                }
            }
        }
    }

    // =======================================================
    // 2. RENDERIZADO
    // =======================================================

    function renderGame() {
        gridEl.innerHTML = '';
        wordsEl.innerHTML = '';

        for (let r = 0; r < GRID_SIZE; r++) {
            for (let c = 0; c < GRID_SIZE; c++) {
                const cell = document.createElement('div');
                cell.className = 'cell';
                cell.id = `cell-${r}-${c}`;
                cell.dataset.row = r;
                cell.dataset.col = c;
                cell.textContent = grid[r][c];
                gridEl.appendChild(cell);
            }
        }

        WORDS.sort().forEach(word => {
            const li = document.createElement('li');
            li.id = `word-${word}`;
            li.textContent = word;
            wordsEl.appendChild(li);
        });

        foundCountEl.textContent = '0';
    }

    // =======================================================
    // 3. MANEJO DE SELECCIÓN
    // (Funciones getCellFromEvent, handleStart, handleMove, handleEnd, highlightCells, getCellsBetween, updateSelection)
    // Se mantienen igual que la versión anterior por claridad, pero se omiten aquí para no duplicar código
    // =======================================================

    function getCellFromEvent(event) {
        const target = event.targetTouches ? event.targetTouches[0].target : event.target;
        if (target.classList.contains('cell')) {
            return target;
        }
        if (event.touches) {
            const touch = event.touches[0];
            return document.elementFromPoint(touch.clientX, touch.clientY);
        }
        return null;
    }

    function handleStart(event) {
        if(foundWords.size === WORDS.length) return;
        event.preventDefault();
        const cell = getCellFromEvent(event);
        if (cell && cell.classList.contains('cell') && !cell.classList.contains('found')) {
            isSelecting = true;
            startCell = cell;
            highlightCells([cell]);
        }
    }

    function handleMove(event) {
        if (!isSelecting) return;
        event.preventDefault();
        const cell = getCellFromEvent(event);
        if (cell && cell.classList.contains('cell') && !cell.classList.contains('found')) {
            updateSelection(cell);
        }
    }

    function handleEnd(event) {
        if (!isSelecting) return;
        isSelecting = false;
        checkWord();
        startCell = null;
        currentCells = [];
    }

    function highlightCells(cells) {
        document.querySelectorAll('.cell.highlight').forEach(c => c.classList.remove('highlight'));
        cells.forEach(c => c.classList.add('highlight'));
    }

    function getCellsBetween(start, end) {
        const sr = parseInt(start.dataset.row);
        const sc = parseInt(start.dataset.col);
        const er = parseInt(end.dataset.row);
        const ec = parseInt(end.dataset.col);

        const dr = Math.sign(er - sr); 
        const dc = Math.sign(ec - sc);

        if (dr !== 0 && dc !== 0 && Math.abs(er - sr) !== Math.abs(ec - sc)) return [start];
        if (dr === 0 && dc === 0) return [start];

        const cells = [];
        let r = sr;
        let c = sc;

        while (r >= 0 && r < GRID_SIZE && c >= 0 && c < GRID_SIZE) {
            const cell = document.getElementById(`cell-${r}-${c}`);
            if (cell) cells.push(cell);
            if (r === er && c === ec) break;

            if (dr === 0 && Math.sign(er - r) !== 0) break; 
            if (dc === 0 && Math.sign(ec - c) !== 0) break;

            r += dr;
            c += dc;
        }
        return cells;
    }

    function updateSelection(endCell) {
        currentCells = getCellsBetween(startCell, endCell);
        highlightCells(currentCells);
    }

    // =======================================================
    // 4. VERIFICACIÓN (Punto de integración de la voz)
    // =======================================================

    function checkWord() {
        if (currentCells.length < 2) {
            highlightCells([]);
            return;
        }

        const selectedCellIds = currentCells.map(c => c.id).sort().join('-');
        let matchedWordObj = null;

        placedWords.forEach(pWord => {
            const pWordIds = pWord.cells.map(cell => `cell-${cell.r}-${cell.c}`).sort().join('-');

            if (pWordIds === selectedCellIds) {
                matchedWordObj = pWord;
            }
        });

        if (matchedWordObj && !foundWords.has(matchedWordObj.word)) {
            const matchedWord = matchedWordObj.word;
            foundWords.add(matchedWord);

            // 🎙️ ¡AQUÍ ESTÁ LA MAGIA!
            speakWord(matchedWord); 

            feedbackEl.textContent = `¡Encontraste la palabra "${matchedWord}"!`;
            feedbackEl.style.color = '#28a745';

            currentCells.forEach(cell => cell.classList.add('found'));
            document.getElementById(`word-${matchedWord}`).classList.add('found-word');

            foundCountEl.textContent = foundWords.size;

            if (foundWords.size === WORDS.length) {
                stopTimer();
                showScore();
            }
        } else {
            feedbackEl.textContent = `Selección incorrecta.`;
            feedbackEl.style.color = '#dc3545';
            setTimeout(() => {
                highlightCells([]); 
                feedbackEl.textContent = '';
            }, 700);
        }
        highlightCells(matchedWordObj ? currentCells : []);
    }

    // =======================================================
    // 5. CRONÓMETRO Y CALIFICACIÓN
    // (Funciones startTimer, stopTimer, showScore)
    // =======================================================

    function startTimer() {
        startTime = Date.now();
        timerInterval = setInterval(() => {
            const elapsedSeconds = Math.floor((Date.now() - startTime) / 1000);
            const minutes = String(Math.floor(elapsedSeconds / 60)).padStart(2, '0');
            const seconds = String(elapsedSeconds % 60).padStart(2, '0');
            timerEl.textContent = `${minutes}:${seconds}`;
        }, 1000);
    }

    function stopTimer() {
        clearInterval(timerInterval);
    }

    function showScore() {
        const totalTimeSeconds = Math.floor((Date.now() - startTime) / 1000);
        const minutes = String(Math.floor(totalTimeSeconds / 60)).padStart(2, '0');
        const seconds = String(totalTimeSeconds % 60).padStart(2, '0');

        let scoreText = '';

        if (totalTimeSeconds <= 180) { // Menos de 3 minutos
            scoreText = `¡Excelente! 🌟 Lo completaste en ${minutes}:${seconds}. Eres un/a maestro/a de los verbos irregulares.`;
            finalScoreEl.style.backgroundColor = '#d4edda';
            finalScoreEl.style.color = '#155724';
        } else if (totalTimeSeconds <= 300) { // Menos de 5 minutos
            scoreText = `¡Muy Bien! 👍 Lo terminaste en ${minutes}:${seconds}. Tienes un buen dominio de los verbos.`;
            finalScoreEl.style.backgroundColor = '#fff3cd';
            finalScoreEl.style.color = '#856404';
        } else {
            scoreText = `¡Buen trabajo! 💪 Lo completaste en ${minutes}:${seconds}. Con más práctica, ¡serás aún más rápido!`;
            finalScoreEl.style.backgroundColor = '#f8d7da';
            finalScoreEl.style.color = '#721c24';
        }

        feedbackEl.textContent = '¡Juego Terminado!';
        feedbackEl.style.color = '#007bff';
        finalScoreEl.innerHTML = scoreText;
        finalScoreEl.style.display = 'block';
    }

    // =======================================================
    // 6. INICIALIZACIÓN
    // =======================================================

    function addEventListeners() {
        // Eventos para el MOUSE (Desktop)
        gridEl.addEventListener('mousedown', handleStart);
        gridEl.addEventListener('mousemove', handleMove);
        document.addEventListener('mouseup', handleEnd);

        // Eventos para TOUCH (Móvil)
        gridEl.addEventListener('touchstart', handleStart);
        gridEl.addEventListener('touchmove', handleMove);
        gridEl.addEventListener('touchend', handleEnd);
    }

    function initGame() {
        generateGrid();
        renderGame();
        addEventListeners();
        startTimer();
    }

    initGame();
</script>","textFeedbackInput":"Show Feedback","textFeedbackTextarea":""}

{"ideviceId":"20251110114347613DAT","textInfoDurationInput":"","textInfoDurationTextInput":"Duration","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Grouping","textTextarea":"<p><br /></p>
<style>
body { font-family: Arial, sans-serif; margin: 25px auto; line-height: 1.6; }
h1 { text-align:center; }
button { padding:10px 16px; margin:6px; font-size:16px; cursor:pointer; border-radius:6px; }
#verb { font-size:32px; text-align:center; margin:20px 0; }
#result { font-size:22px; text-align:center; margin-top:12px; }
.correct { color:green; font-weight:bold; }
.incorrect { color:red; font-weight:bold; }
</style>
<h1>Práctica de Pronunciación</h1>
<p>Presiona <strong>“Escuchar”</strong> para oír el verbo. Luego presiona <strong>“Hablar”</strong> y repítelo en voz alta. El sistema comparará tu pronunciación.</p>
<div id="verb">click en "Siguiente"</div>
<div style="text-align: center;"><button onclick="play()">🔊 Escuchar</button> <button onclick="record()">🎤 Hablar</button> <button onclick="nextVerb()">➡️ Siguiente</button></div>
<div id="result"></div>
<p>
<script>
const verbs = ["go","went","gone","eat","ate","eaten","run","ran","run","write","wrote","written","see","saw","seen"];
let current = null;

function nextVerb(){
  current = verbs[Math.floor(Math.random()*verbs.length)];
  document.getElementById("verb").textContent = current;
  document.getElementById("result").textContent = "";
}

function play(){
  const ut = new SpeechSynthesisUtterance(current);
  ut.lang = "en-US";
  speechSynthesis.speak(ut);
}

function record(){
  if(!('webkitSpeechRecognition' in window)){ alert("Tu navegador no soporta reconocimiento de voz."); return;}
  const rec = new webkitSpeechRecognition();
  rec.lang = "en-US";
  rec.onresult = e => {
    const spoken = e.results[0][0].transcript.toLowerCase().trim();
    const result = document.getElementById("result");
    if (spoken === current) {
      result.innerHTML = `<span class="correct">✔ Muy bien: "${spoken}"</span>`;
    } else {
      result.innerHTML = `<span class="incorrect">✘ Dijiste "${spoken}". Intenta de nuevo.</span>`;
    }
  };
  rec.start();
}

nextVerb();
</script>
</p>","textFeedbackInput":"Show Feedback","textFeedbackTextarea":""}

{"ideviceId":"20251110122159102YFG","textInfoDurationInput":"","textInfoDurationTextInput":"Duration","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Grouping","textTextarea":"<p><br /></p>
<style>
body { font-family: Georgia, serif; margin: 30px auto; line-height: 1.7; color:#222; }
h1 { text-align:center; }
button { padding: 10px 16px; margin: 6px; font-size: 16px; cursor:pointer; border-radius:6px; border: 1px solid #444;}
button:hover { background:#ddd; }
#sceneText { margin: 18px 0; font-size: 20px; }
.choice-container { margin-top:18px; }
#speakBtn { background:#444; color:white; }
</style>
<h1>🔍 The Case of the Missing Key</h1>
<p><em>Lee la historia y elige lo que sucede a continuación. Cada escena será narrada en inglés con voz femenina.</em></p>
<div id="sceneText"></div>
<div style="text-align: center;"><button id="speakBtn" onclick="speakScene()">🔊 Repetir narración</button></div>
<div id="choices" class="choice-container"></div>
<div id="end" style="display: none; margin-top: 30px; padding: 16px; border-top: 2px solid #333;">
<h2>Ahora es tu turno ✍️</h2>
<p>Escribe tu propia versión del final o crea una historia alternativa (5-8 oraciones) usando <strong>al menos 6 verbos irregulares</strong> en pasado.</p>
<p>Cuando termines, súbelo en la sección de entrega de la actividad.</p>
</div>
<script>
// ---------- STORY DATA ----------
const scenes = {
 start: {
   text: "Last night, you walked down a dark street. Suddenly, you found an old key on the ground. You picked it up and looked around. Nobody was there. What did you do next?",
   choices: [
     { label: "I went to an abandoned house I remembered.", goto: "house" },
     { label: "I kept the key and went back home.", goto: "home" }
   ]
 },
 house: {
   text: "You went to the abandoned house. The door was locked. You tried the key... it fit. When you opened the door, you heard something moving inside.",
   choices: [
     { label: "I entered slowly.", goto: "inside" },
     { label: "I ran away.", goto: "runaway" }
   ]
 },
 home: {
   text: "You kept the key and went home. But while you slept, you heard a metallic sound. You woke up and saw the key on the floor again.",
   choices: [
     { label: "I took it and called a friend.", goto: "friend" },
     { label: "I ignored it and went back to sleep.", goto: "end_badvibes" }
   ]
 },
 inside: {
   text: "You entered slowly. The house was silent. On a table, there was an old book. You opened it and saw your name written inside.",
   choices: [
     { label: "I took the book.", goto: "book" },
     { label: "I left it and looked in another room.", goto: "hallway" }
   ]
 },
 runaway: {
   text: "You ran as fast as you could. But you heard footsteps behind you...",
   choices: [
     { label: "I hid behind a car.", goto: "hide" },
     { label: "I shouted for help.", goto: "shout" }
   ]
 },
 friend: {
   text: "You called your friend. He came, looked at the key and said: 'I have seen this before... It belonged to someone who disappeared years ago.'",
   choices: [
     { label: "We went to investigate.", goto: "house" },
     { label: "I decided to stop.", goto: "end_safe" }
   ]
 },
 end_badvibes: {
   text: "You ignored the key. But when you woke up, it was in your hand. You never discovered its origin.",
   end: true
 },
 book: {
   text: "You took the book. The house began to fill with noise. The key glowed in your pocket.",
   choices: [
     { label: "I ran outside.", goto: "end_run" },
     { label: "I stayed to investigate.", goto: "end_courage" }
   ]
 },
 hallway: {
   text: "You walked through the hallway. A shadow crossed in front of you. It watched you... and disappeared.",
   choices: [
     { label: "I followed it.", goto: "end_courage" },
     { label: "I ran outside.", goto: "end_run" }
   ]
 },
 hide: {
   text: "You hid behind a car. The footsteps stopped behind you... then faded away.",
   choices: [
     { label: "I returned to the house.", goto: "house" },
     { label: "I went home.", goto: "home" }
   ]
 },
 shout: {
   text: "You shouted. But nobody answered.",
   choices: [
     { label: "I returned to the house.", goto: "house" },
     { label: "I went home.", goto: "home" }
   ]
 },
 end_run: { text: "You escaped. But the mystery remained unsolved.", end: true },
 end_courage: { text: "You stayed. The shadow returned. You were not afraid. The key was not the beginning... but an invitation.", end: true },
 end_safe: { text: "You chose safety. Some stories are better left closed.", end: true }
};

// ---------- RENDER + NARRATION ----------
let current = "start";
let voice = null;

function selectVoice() {
  const voices = speechSynthesis.getVoices();
  voice = voices.find(v => v.lang === "en-US" && /female/i.test(v.name)) || voices.find(v => v.lang === "en-US");
}
speechSynthesis.onvoiceschanged = selectVoice;

function speakScene() {
  if (!voice) selectVoice();
  let msg = new SpeechSynthesisUtterance(scenes[current].text);
  msg.voice = voice;
  msg.rate = 0.97;
  speechSynthesis.speak(msg);
}

function render() {
  let s = scenes[current];
  document.getElementById("sceneText").innerHTML = s.text;

  if(s.end){
    document.getElementById("choices").innerHTML = "";
    document.getElementById("end").style.display = "block";
  } else {
    document.getElementById("choices").innerHTML =
      s.choices.map(c => `<button onclick="go('${c.goto}')">${c.label}</button>`).join("");
  }

  speakScene();
}

function go(next){ speechSynthesis.cancel(); current=next; render(); }
render();
</script>","textFeedbackInput":"Show Feedback","textFeedbackTextarea":""}

{"ideviceId":"20251107153630722O6K","textInfoDurationInput":"","textInfoDurationTextInput":"Duration","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Grouping","textTextarea":"<div style="font-family: Arial, sans-serif; font-size: 17px; line-height: 1.6;">
<h2>Producción escrita (Verbos irregulares)</h2>
<p>Escribe un texto usando <strong>al menos 6 verbos irregulares distintos</strong> en pasado o participio. Después comparte un audio leyendo tu texto.</p>
<h3>Opción 1.- Entrega por cliente de correo electrónico.</h3>
<label>Nombre completo:</label> <input id="studentName" type="text" style="width: 100%;" required="" /> <label>Correo electrónico:</label> <input id="studentEmail" type="email" style="width: 100%;" required="" /> <label>Tu texto (5–8 oraciones):</label> <textarea id="studentText" style="width: 100%; height: 150px;" required="" oninput="processText()"></textarea>
<p><strong>Verbos irregulares detectados:</strong> <span id="count">0</span></p>
<p><strong>Verbos distintos:</strong> <span id="uniqueCount">0</span></p>
<div id="highlightBox" style="border: 1px solid #ccc; padding: 10px; min-height: 100px;"></div>
<p><strong>Verbos usados:</strong> <span id="usedList"></span></p>
<p id="suggestions" style="color: #a00;"></p>
<p id="verbCheck" style="color: #a00; font-weight: bold; display: none;"></p>
<label>Enlace a tu audio (Drive / Dropbox / OneDrive):</label> <input id="audioLink" type="text" style="width: 100%;" placeholder="https://..." />
<p><button onclick="speakText()">🔊 Escuchar mi texto</button></p>
<button onclick="sendMail()">📨 Generar correo de envío</button>
<p id="result"></p>
<p><strong>La entrega será enviada a:</strong> jose.torres.osorio@gmail.com</p>
</div>
<p>
<script>
const irregulars = [
"went","gone","go","ate","eaten","eat","saw","seen","see","took","taken","take",
"gave","given","give","came","come","drank","drunk","drink","ran","run","spoke","spoken","speak",
"wrote","written","write","felt","feel","found","find","knew","known","know","began","begun","begin",
"broke","broken","break","bought","buy","brought","bring","built","build","chose","chosen","choose",
"did","done","do","drove","driven","drive","fell","fallen","fall","flew","flown","fly","got","gotten","get",
"heard","hear","kept","keep","lost","lose","made","make","paid","pay","read","read","rode","ridden","ride",
"sold","sell","sent","send","sat","sit","slept","sleep"
];

// (D+E+F) detección, conteo y sugerencias
function processText(){
  const raw = studentText.value;
  const words = raw.toLowerCase().replace(/[^a-z\s]/g,"").split(/\s+/);
  const matches = words.filter(w => irregulars.includes(w));

  document.getElementById("count").textContent = matches.length;

  // Verbos únicos
  const unique = [...new Set(matches)];
  document.getElementById("uniqueCount").textContent = unique.length;

  // Resaltado
  document.getElementById("highlightBox").innerHTML = raw.split(/\s+/).map(word=>{
    const clean = word.toLowerCase().replace(/[^a-z]/g,"");
    return irregulars.includes(clean) ? `<span style="background:yellow;">${word}</span>` : word;
  }).join(" ");

  // Mostrar lista de verbos usados
  document.getElementById("usedList").textContent = unique.join(", ") || "(ninguno)";

  // Sugerencias por repetición
  let suggestions = "";
  unique.forEach(v=>{
    const count = matches.filter(x=>x===v).length;
    if(count > 2){
      suggestions += `Estás usando mucho <strong>${v}</strong>. Intenta variar.<br>`;
    }
  });
  document.getElementById("suggestions").innerHTML = suggestions;
}

// Envío sólo si hay >= 6 verbos únicos
function sendMail(){
  const name = studentName.value.trim();
  const email = studentEmail.value.trim();
  const text = studentText.value.trim();
  const audio = audioLink.value.trim();

  const uniqueCount = parseInt(document.getElementById("uniqueCount").textContent);

  if(uniqueCount < 6){
    verbCheck.style.display="block";
    verbCheck.textContent="⚠️ Necesitas al menos 6 verbos irregulares distintos. Tienes: " + uniqueCount;
    return;
  }

  const teacher = "jose.torres.osorio@gmail.com";
  const subject = encodeURIComponent("Entrega OVA — " + name);
  let body = `Nombre: ${encodeURIComponent(name)}%0D%0A`;
  body += `Correo: ${encodeURIComponent(email)}%0D%0A%0D%0A`;
  body += `Texto:%0D%0A${encodeURIComponent(text)}%0D%0A%0D%0A`;
  body += `Audio: ${encodeURIComponent(audio || "(no adjunto)")}%0D%0A`;

  window.location.href = `mailto:${teacher}?subject=${subject}&body=${body}`;
  result.textContent="✔ Se abrió tu correo. Envía para completar la entrega.";
}

function speakText(){
  const msg = new SpeechSynthesisUtterance(studentText.value);
  msg.lang = "en-US";
  msg.rate = 0.95;
  speechSynthesis.speak(msg);
}
</script>
</p>","textFeedbackInput":"Show Feedback","textFeedbackTextarea":""}

